"""Sala previa autosuficiente para comprobar dispositivos antes de una reunión."""

import json


def build_prejoin_html(*, logo: str, meeting: dict, participant_name: str, participant_count: int) -> str:
    config = json.dumps(
        {
            "logo": logo,
            "title": str(meeting.get("tema") or "Reunión VINCORA"),
            "joinUrl": str(meeting.get("join_url") or meeting.get("start_url") or ""),
            "name": participant_name,
            "participantCount": participant_count,
        },
        ensure_ascii=False,
    ).replace("</", "<\\/")
    return _DOCUMENT.replace("__CONFIG__", config)


_DOCUMENT = r'''<!doctype html>
<html lang="es">
<head>
<meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<style>
*{box-sizing:border-box}html,body{margin:0;min-height:100%;font-family:"Segoe UI",Arial,sans-serif;color:#101d40;background:radial-gradient(circle at 50% 18%,#fff 0,#f7faff 44%,#edf4ff 100%)}
button,select,input{font:inherit}.topbar{height:72px;padding:0 30px;display:flex;align-items:center;justify-content:space-between;background:#fff;border-bottom:1px solid #dce4f0;box-shadow:0 2px 6px #1633610a}.brand{display:flex;align-items:center;gap:10px}.brand img{width:45px;height:45px;object-fit:contain}.brand-name{font-size:20px;font-weight:800}.brand-tag{font-size:11px;color:#65728d;margin-top:2px}.top-actions{display:flex;gap:38px}.top-action{border:0;background:transparent;color:#1e3155;display:flex;align-items:center;gap:10px;cursor:pointer}.circle-icon{width:24px;height:24px;border:1.7px solid currentColor;border-radius:50%;display:grid;place-items:center;font-weight:700}.gear{font-size:25px}.page{max-width:1320px;margin:auto;padding:22px 40px 32px}.heading{text-align:center;margin-bottom:24px}.heading h1{margin:0;font-size:34px;line-height:1.1;letter-spacing:-.8px}.heading h2{margin:8px 0 0;font-size:23px}.main-grid{display:grid;grid-template-columns:1.4fr 1fr;gap:22px}.preview{position:relative;min-height:505px;overflow:hidden;border-radius:22px;background:#15223c;box-shadow:0 7px 22px #172e5720}.preview video{width:100%;height:100%;position:absolute;inset:0;object-fit:cover;transform:scaleX(-1);background:linear-gradient(135deg,#243a62,#0c1528)}.preview.blur video{filter:blur(10px);transform:scaleX(-1) scale(1.04)}.preview.office:after{content:"";position:absolute;inset:0;background:linear-gradient(120deg,#dbe9f3aa,#ffffff22 40%,#6f849d66);mix-blend-mode:soft-light;pointer-events:none}.preview-label{position:absolute;z-index:2;top:16px;left:20px;padding:8px 22px;color:#fff;background:#111b28a8;border-radius:30px}.permission-message{position:absolute;z-index:2;inset:0;display:grid;place-items:center;padding:70px;text-align:center;color:#fff;background:linear-gradient(135deg,#23395f,#111b31)}.permission-message button{margin-top:16px;padding:12px 22px;border:0;border-radius:9px;color:#fff;background:#1765ed;cursor:pointer}.preview-controls{position:absolute;z-index:3;bottom:28px;left:50%;display:flex;gap:32px;transform:translateX(-50%)}.round-control{display:flex;flex-direction:column;align-items:center;gap:8px;color:#fff;font-size:13px}.round-control button{width:68px;height:68px;border:2px solid #2465ee;border-radius:50%;background:#fff;color:#27405f;font-size:28px;cursor:pointer}.round-control.off button{background:#e7ebf3;color:#8792a5;text-decoration:line-through}.settings{padding:20px 28px;border:1px solid #d8e0ec;border-radius:17px;background:#ffffffed;box-shadow:0 8px 25px #1b376012}.field-title{font-weight:700;margin-bottom:8px}.name-field{position:relative;margin-bottom:20px}.name-field input{width:100%;height:47px;padding:0 48px 0 16px;border:1.5px solid #1765ed;border-radius:7px;font-size:18px}.edit{position:absolute;right:16px;top:10px;color:#1765ed;font-size:24px}.device-row{display:grid;grid-template-columns:30px 105px 1fr;align-items:center;gap:8px;margin:12px 0}.device-icon{color:#1765ed;font-size:24px}.device-row select{width:100%;height:41px;padding:0 14px;border:1px solid #d5deea;border-radius:7px;background:#fff;color:#263a5c}.audio-title{margin-top:16px;font-weight:700}.meter{height:18px;margin:8px 0 16px;display:flex;gap:5px;align-items:center}.meter i{width:5px;height:13px;border-radius:3px;background:#dfe4ec}.meter i.active{background:#36b968}.backgrounds{display:grid;grid-template-columns:repeat(3,1fr);gap:16px}.background-choice{border:0;background:none;color:#243657;cursor:pointer}.thumb{height:74px;border:1px solid #d5deea;border-radius:10px;background:#fff;display:grid;place-items:center;font-size:40px;overflow:hidden}.background-choice.active .thumb{border:2px solid #1765ed}.thumb.blur-thumb{background:linear-gradient(135deg,#d8d0c5,#8f9a91);filter:blur(.6px)}.thumb.office-thumb{background:linear-gradient(160deg,#91a0ad 0 35%,#d8c7af 36% 55%,#525d68 56%)}.background-choice span{display:block;margin-top:7px}.remember{display:flex;gap:10px;align-items:center;margin-top:16px}.remember input,.consent input{width:20px;height:20px;accent-color:#1765ed}.consent{margin-top:20px;padding:14px 20px;min-height:94px;display:grid;grid-template-columns:62px 1.35fr 1px 1.25fr;align-items:center;gap:20px;border:1px solid #d7e1ef;border-radius:14px;background:#fff;box-shadow:0 7px 20px #1b37600e}.shield{width:62px;height:62px;border-radius:50%;display:grid;place-items:center;color:#fff;font-size:30px;background:linear-gradient(135deg,#3d8af7,#933cf2)}.consent h3{margin:0 0 7px;font-size:18px}.consent p{margin:0;color:#5f6f8b}.divider{height:54px;background:#d9e1ec}.consent label{display:flex;align-items:center;gap:12px;color:#435575}.bottom-actions{display:flex;justify-content:center;gap:18px;margin-top:20px}.action{min-width:220px;height:58px;border-radius:10px;border:1.5px solid #1765ed;background:#fff;color:#1765ed;font-size:18px;font-weight:700;cursor:pointer}.action.primary{border:0;color:#fff;background:linear-gradient(105deg,#1765ed,#4a66f4 58%,#923ff1)}.action.primary:disabled{opacity:.45;cursor:not-allowed}.participants{text-align:center;margin-top:15px;color:#283c61}.participants b{color:#1765ed;font-size:21px;margin-right:9px}.toast{position:fixed;right:24px;bottom:24px;padding:12px 17px;border-radius:8px;background:#132445;color:#fff;opacity:0;transition:.2s}.toast.show{opacity:1}
@media(max-width:900px){.page{padding:18px}.main-grid{grid-template-columns:1fr}.preview{min-height:420px}.consent{grid-template-columns:55px 1fr}.divider{display:none}.consent label{grid-column:1/-1}.top-actions{gap:12px}.top-action span:last-child{display:none}}@media(max-width:560px){.heading h1{font-size:27px}.heading h2{font-size:18px}.settings{padding:18px}.device-row{grid-template-columns:26px 82px 1fr}.bottom-actions{flex-direction:column}.action{width:100%}.consent{padding:14px}.page{padding:14px}.preview{min-height:330px}}
</style></head>
<body>
<header class="topbar"><div class="brand"><img id="logo" alt="VINCORA Meet"><div><div class="brand-name">VINCORA Meet</div><div class="brand-tag">Conecta. Reúnete. Avanza.</div></div></div><div class="top-actions"><button class="top-action" id="help"><span class="circle-icon">?</span><span>Ayuda</span></button><button class="top-action" id="configure"><span class="gear">⚙</span><span>Configuración</span></button></div></header>
<main class="page"><div class="heading"><h1>¿Preparado para unirte?</h1><h2 id="meeting-title"></h2></div>
<div class="main-grid"><section class="preview" id="preview"><video id="video" autoplay muted playsinline></video><div class="permission-message" id="permission"><div><strong>Comprueba tu cámara y micrófono</strong><br><button id="allow">Permitir dispositivos</button></div></div><span class="preview-label">Vista previa</span><div class="preview-controls"><div class="round-control" id="mic-wrap"><button id="mic-toggle" aria-label="Micrófono">♩</button><span>Micrófono</span></div><div class="round-control" id="camera-wrap"><button id="camera-toggle" aria-label="Cámara">▣</button><span>Cámara</span></div></div></section>
<section class="settings"><div class="field-title">Tu nombre</div><div class="name-field"><input id="name" aria-label="Tu nombre"><span class="edit">✎</span></div><div class="device-row"><span class="device-icon">▣</span><span>Cámara</span><select id="camera" aria-label="Cámara"></select></div><div class="device-row"><span class="device-icon">♩</span><span>Micrófono</span><select id="microphone" aria-label="Micrófono"></select></div><div class="device-row"><span class="device-icon">◖))</span><span>Altavoces</span><select id="speaker" aria-label="Altavoces"></select></div><div class="audio-title">Nivel de audio</div><div class="meter" id="meter"></div><div class="field-title">Fondo</div><div class="backgrounds"><button class="background-choice active" data-background="none"><div class="thumb">⊘</div><span>Ninguno</span></button><button class="background-choice" data-background="blur"><div class="thumb blur-thumb"></div><span>Desenfoque</span></button><button class="background-choice" data-background="office"><div class="thumb office-thumb"></div><span>Oficina</span></button></div><label class="remember"><input type="checkbox" id="remember" checked>Recordar mis dispositivos</label></section></div>
<section class="consent"><div class="shield">✓</div><div><h3>Grabación y transcripción con IA</h3><p>Esta reunión será grabada y transcrita para generar un informe automático.</p></div><div class="divider"></div><label><input type="checkbox" id="consent">Acepto la grabación y el procesamiento del audio.</label></section><div class="bottom-actions"><button class="action" id="back">← &nbsp; Volver</button><button class="action primary" id="join" disabled>Unirse ahora &nbsp; →</button></div><div class="participants"><b>♧</b><span id="participant-text"></span></div></main><div class="toast" id="toast"></div>
<script>
const cfg=__CONFIG__; document.getElementById('logo').src=cfg.logo;document.getElementById('meeting-title').textContent=cfg.title;document.getElementById('name').value=localStorage.getItem('vincora-prejoin-name')||cfg.name;document.getElementById('participant-text').textContent=cfg.participantCount+' participantes ya están conectados';
try{window.frameElement.setAttribute('allow','camera; microphone; autoplay')}catch(e){}
const video=document.getElementById('video'),permission=document.getElementById('permission'),cameraSelect=document.getElementById('camera'),micSelect=document.getElementById('microphone'),speakerSelect=document.getElementById('speaker'),meter=document.getElementById('meter');let stream=null,audioContext=null,analyser=null,meterFrame=null;
for(let i=0;i<30;i++){const bar=document.createElement('i');meter.appendChild(bar)}
const toast=t=>{const el=document.getElementById('toast');el.textContent=t;el.classList.add('show');setTimeout(()=>el.classList.remove('show'),2200)};
async function devices(){const list=await navigator.mediaDevices.enumerateDevices();const fill=(select,kind,fallback)=>{const old=select.value;select.innerHTML='';list.filter(d=>d.kind===kind).forEach((d,i)=>{const o=document.createElement('option');o.value=d.deviceId;o.textContent=d.label||fallback+' '+(i+1);select.appendChild(o)});if(old)select.value=old;if(!select.options.length){const o=document.createElement('option');o.textContent='No disponible';select.appendChild(o)}};fill(cameraSelect,'videoinput','Cámara');fill(micSelect,'audioinput','Micrófono');fill(speakerSelect,'audiooutput','Altavoces')}
function stop(){if(stream)stream.getTracks().forEach(t=>t.stop());if(meterFrame)cancelAnimationFrame(meterFrame)}
async function start(){stop();try{stream=await navigator.mediaDevices.getUserMedia({video:cameraSelect.value?{deviceId:{exact:cameraSelect.value}}:true,audio:micSelect.value?{deviceId:{exact:micSelect.value}}:true});video.srcObject=stream;permission.style.display='none';await devices();startMeter();remember()}catch(e){permission.style.display='grid';permission.querySelector('strong').textContent='No se pudo acceder a cámara o micrófono';toast('Revisa los permisos del navegador')}}
function startMeter(){try{audioContext=audioContext||new AudioContext();analyser=audioContext.createAnalyser();audioContext.createMediaStreamSource(stream).connect(analyser);const data=new Uint8Array(analyser.frequencyBinCount);const draw=()=>{analyser.getByteFrequencyData(data);const level=Math.min(30,Math.round(data.reduce((a,b)=>a+b,0)/data.length/4));[...meter.children].forEach((b,i)=>b.classList.toggle('active',i<level));meterFrame=requestAnimationFrame(draw)};draw()}catch(e){}}
function remember(){if(document.getElementById('remember').checked)localStorage.setItem('vincora-prejoin-devices',JSON.stringify({camera:cameraSelect.value,mic:micSelect.value,speaker:speakerSelect.value}))}
document.getElementById('allow').onclick=start;cameraSelect.onchange=start;micSelect.onchange=start;speakerSelect.onchange=async()=>{try{if(video.setSinkId)await video.setSinkId(speakerSelect.value);remember();const ctx=new AudioContext();const osc=ctx.createOscillator(),gain=ctx.createGain();gain.gain.value=.08;osc.connect(gain).connect(ctx.destination);osc.start();osc.stop(ctx.currentTime+.18);toast('Altavoces comprobados')}catch(e){toast('El navegador no permite seleccionar la salida')}};
document.getElementById('camera-toggle').onclick=()=>{if(!stream)return start();const t=stream.getVideoTracks()[0];t.enabled=!t.enabled;document.getElementById('camera-wrap').classList.toggle('off',!t.enabled)};document.getElementById('mic-toggle').onclick=()=>{if(!stream)return start();const t=stream.getAudioTracks()[0];t.enabled=!t.enabled;document.getElementById('mic-wrap').classList.toggle('off',!t.enabled)};
document.querySelectorAll('.background-choice').forEach(b=>b.onclick=()=>{document.querySelectorAll('.background-choice').forEach(x=>x.classList.remove('active'));b.classList.add('active');document.getElementById('preview').className='preview '+(b.dataset.background==='none'?'':b.dataset.background)});
const consent=document.getElementById('consent'),join=document.getElementById('join');consent.onchange=()=>join.disabled=!consent.checked;document.getElementById('name').onchange=e=>localStorage.setItem('vincora-prejoin-name',e.target.value.trim());document.getElementById('remember').onchange=remember;
join.onclick=()=>{if(!cfg.joinUrl)return toast('Esta reunión aún no tiene enlace de acceso');remember();stop();window.open(cfg.joinUrl,'_blank','noopener')};document.getElementById('back').onclick=()=>{stop();window.parent.location.href='?pagina=Reuniones'};document.getElementById('help').onclick=()=>toast('Permite cámara y micrófono para comprobarlos');document.getElementById('configure').onclick=()=>{document.querySelector('.settings').scrollIntoView({behavior:'smooth'});toast('Selecciona aquí tus dispositivos')};window.addEventListener('beforeunload',stop);
devices().then(()=>{try{const saved=JSON.parse(localStorage.getItem('vincora-prejoin-devices')||'{}');if(saved.camera)cameraSelect.value=saved.camera;if(saved.mic)micSelect.value=saved.mic;if(saved.speaker)speakerSelect.value=saved.speaker}catch(e){}});
</script></body></html>'''
